parameters.jsCode:
const now = new Date();
const input = $input.first().json;
const events = input.items || [];
const toSend = [];

for (const event of events) {
  if (!event.start || !event.start.dateTime) continue;

  const start = new Date(event.start.dateTime);
  const diffMs = start - now;
  const diffHours = diffMs / (1000 * 60 * 60);

  const is24hr = diffHours >= 23.5 && diffHours <= 24.5;
  const is1hr = diffHours >= 0.5 && diffHours <= 1.5;

  if (is24hr || is1hr) {
    const desc = event.description || '';

    const phone = (desc.match(/WhatsApp Number:\s*(\d+)/) || [])[1] || '';
    const name = (desc.match(/Patient Name:\s*([\w\s]+?)(?=WhatsApp|Date:|Clinic:|$)/) || [])[1]?.trim() || '';
    const service = (desc.match(/Appointment Type:\s*([\w\s\/]+?)(?=Patient|WhatsApp|Date:|$)/) || [])[1]?.trim() || event.summary || '';

    toSend.push({
      json: {
        phone,
        name,
        service,
        date: start.toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', day: 'numeric', month: 'long', year: 'numeric' }),
        time: start.toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' }),
        reminder_type: is24hr ? '24hr' : '1hr'
      }
    });
  }
}

return toSend.length > 0 ? toSend : [{ json: { skip: true } }];

